// ── STEP 1: Validate incoming WooCommerce order payload ──
const body = $input.first().json.body || $input.first().json;

// Required fields check
const requiredFields = ['id', 'status', 'total', 'billing', 'line_items'];
const missingFields = requiredFields.filter(f => !body[f]);
if (missingFields.length > 0) {
  throw new Error(`WooCommerce payload missing required fields: ${missingFields.join(', ')}`);
}

// Only process 'processing' orders (payment confirmed)
// 'pending' = awaiting payment, ignore until it becomes 'processing'
const status = (body.status || '').toLowerCase();
if (status !== 'processing') {
  return [{ json: { skip: true, reason: `Status is '${status}', not 'processing'. Ignoring.`, order_id: body.id } }];
}

const lineItems = body.line_items || [];
if (lineItems.length === 0) {
  throw new Error(`Order #${body.id} has no line items — possible corrupted webhook payload`);
}

// Parse order cleanly
const orderTotal = parseFloat(body.total) || 0;
const billing = body.billing || {};
const shipping = body.shipping || {};
const customerEmail = billing.email || '';
const customerName = `${billing.first_name || ''} ${billing.last_name || ''}`.trim();

return [{
  json: {
    skip: false,
    order_id:        body.id,
    order_number:    body.number || body.id,
    status:          status,
    order_total:     orderTotal,
    currency:        body.currency || 'USD',
    customer_email:  customerEmail,
    customer_name:   customerName,
    customer_id:     body.customer_id || 0,
    billing_country: billing.country || '',
    shipping_country: shipping.country || billing.country || '',
    payment_method:  body.payment_method || '',
    payment_method_title: body.payment_method_title || '',
    line_items:      lineItems.map(item => ({
      product_id:   item.product_id,
      product_name: item.name,
      sku:          item.sku || String(item.product_id),
      quantity:     item.quantity,
      subtotal:     parseFloat(item.subtotal) || 0
    })),
    item_count:      lineItems.reduce((sum, i) => sum + i.quantity, 0),
    date_created:    body.date_created || new Date().toISOString(),
    received_at:     new Date().toISOString()
  }
}];

// ── STEP 2: Fraud signal detection + stock check ──
// ── Configuration ──
const HIGH_VALUE_THRESHOLD   = 500;   // orders above this are flagged
const VELOCITY_WINDOW_HOURS  = 24;    // look-back window for repeat orders
const VELOCITY_MAX_ORDERS    = 3;     // max orders per customer in window
const FREE_EMAIL_DOMAINS     = ['gmail.com','yahoo.com','hotmail.com','outlook.com','live.com'];

const order       = $('Validate & Parse Order').item.json;
const recentRows  = $('Read Recent Orders').all();
const inventoryRows = $('Read Inventory Sheet').all();

const flags = [];
const warnings = [];

// ─ Flag 1: High value order ─
if (order.order_total >= HIGH_VALUE_THRESHOLD) {
  flags.push(`High value order: ${order.currency} ${order.order_total}`);
}

// ─ Flag 2: Billing/shipping country mismatch ─
if (order.billing_country && order.shipping_country &&
    order.billing_country !== order.shipping_country) {
  flags.push(`Billing country (${order.billing_country}) ≠ shipping country (${order.shipping_country})`);
}

// ─ Flag 3: Customer velocity — too many orders in 24h ─
const cutoff = Date.now() - VELOCITY_WINDOW_HOURS * 3600 * 1000;
const recentByCustomer = recentRows.filter(r => {
  const email = r.json['Customer Email'] || '';
  const created = new Date(r.json['Date Created'] || 0).getTime();
  return email.toLowerCase() === order.customer_email.toLowerCase() && created > cutoff;
});
if (recentByCustomer.length >= VELOCITY_MAX_ORDERS) {
  flags.push(`Velocity: customer placed ${recentByCustomer.length} orders in last ${VELOCITY_WINDOW_HOURS}h`);
}

// ─ Flag 4: Free email domain on high-value order ─
const emailDomain = order.customer_email.split('@')[1] || '';
if (order.order_total >= HIGH_VALUE_THRESHOLD && FREE_EMAIL_DOMAINS.includes(emailDomain.toLowerCase())) {
  warnings.push(`Free email domain (${emailDomain}) on high-value order`);
}

// ─ Flag 5: Guest order (no customer account) on high value ─
if (order.customer_id === 0 && order.order_total >= HIGH_VALUE_THRESHOLD) {
  warnings.push('Guest checkout on high-value order — no account on file');
}

// ─ Stock check ─
const stockIssues = [];
order.line_items.forEach(item => {
  const match = inventoryRows.find(r =>
    (r.json.SKU || '').toString().trim().toLowerCase() === item.sku.toLowerCase()
  );
  if (!match) {
    stockIssues.push(`SKU "${item.sku}" (${item.product_name}) not found in inventory sheet`);
  } else {
    const available = parseInt(match.json['Current Stock']) || 0;
    if (available < item.quantity) {
      stockIssues.push(`SKU "${item.sku}": ordered ${item.quantity}, only ${available} in stock`);
    }
  }
});

if (stockIssues.length > 0) {
  flags.push(`Stock issues: ${stockIssues.join(' | ')}`);
}

const isFlagged   = flags.length > 0;
const hasWarnings = warnings.length > 0;

// Build Slack message for #orders
const itemList = order.line_items.map(i => `• ${i.product_name} × ${i.quantity}`).join('\n');
const slackOrderMsg = [
  `*New Order #${order.order_number}* — ${order.currency} ${order.order_total}`,
  `*Customer:* ${order.customer_name} (${order.customer_email})`,
  `*Items:*\n${itemList}`,
  `*Payment:* ${order.payment_method_title}`,
  isFlagged   ? `\n:warning: *FLAGS:* ${flags.join(' | ')}` : '',
  hasWarnings ? `\n:information_source: *Warnings:* ${warnings.join(' | ')}` : ''
].filter(Boolean).join('\n');

// Build Slack review message (only if flagged)
const N8N_BASE_URL = 'https://n8n.sahcreatives.com';
const encodedOrder = encodeURIComponent(JSON.stringify({ order_id: order.order_id, order_number: order.order_number, flags }));
const approveUrl = `${N8N_BASE_URL}/webhook/order-review?action=approve&data=${encodedOrder}`;
const holdUrl    = `${N8N_BASE_URL}/webhook/order-review?action=hold&data=${encodedOrder}`;
const cancelUrl  = `${N8N_BASE_URL}/webhook/order-review?action=cancel&data=${encodedOrder}`;

const slackReviewMsg = isFlagged ? [
  `:rotating_light: *Order #${order.order_number} flagged for review*`,
  `*Total:* ${order.currency} ${order.order_total}`,
  `*Customer:* ${order.customer_name} (${order.customer_email})`,
  `*Flags:*\n${flags.map(f => `  • ${f}`).join('\n')}`,
  `\n<${approveUrl}|Approve> | <${holdUrl}|Put on Hold> | <${cancelUrl}|Cancel>`
].join('\n') : '';

return [{
  json: {
    ...order,
    flags,
    warnings,
    stock_issues: stockIssues,
    is_flagged: isFlagged,
    has_warnings: hasWarnings,
    slack_order_msg: slackOrderMsg,
    slack_review_msg: slackReviewMsg
  }
}];

const query = $input.first().json.query || {};
const action = (query.action || '').toLowerCase();

if (!['approve','hold','cancel'].includes(action)) {
  throw new Error(`Invalid review action: "${action}". Expected: approve, hold, cancel`);
}
if (!query.data) {
  throw new Error('Missing order data in review URL');
}

let orderData = {};
try {
  orderData = JSON.parse(decodeURIComponent(query.data));
} catch(e) {
  throw new Error(`Could not parse order data from URL: ${e.message}`);
}

if (!orderData.order_id) {
  throw new Error('Order data missing order_id');
}

return [{
  json: {
    action,
    order_id:     orderData.order_id,
    order_number: orderData.order_number,
    flags:        orderData.flags || [],
    reviewed_at:  new Date().toISOString()
  }
}];

