// ── STEP 1: Parse the updated order and detect meaningful status changes ──
const body = $input.first().json.body || $input.first().json;

if (!body.id) {
  throw new Error('Order updated webhook missing order ID');
}

const newStatus = (body.status || '').toLowerCase();
const billing   = body.billing || {};
const shipping  = body.shipping || {};

// Status labels map — what we say to the customer vs internal names
const STATUS_LABELS = {
  'pending':    { label: 'Pending Payment',  customer_facing: false },
  'processing': { label: 'Processing',       customer_facing: true  },
  'on-hold':    { label: 'On Hold',          customer_facing: true  },
  'completed':  { label: 'Completed',        customer_facing: true  },
  'cancelled':  { label: 'Cancelled',        customer_facing: true  },
  'refunded':   { label: 'Refunded',         customer_facing: true  },
  'failed':     { label: 'Payment Failed',   customer_facing: true  }
};

const statusInfo = STATUS_LABELS[newStatus] || { label: newStatus, customer_facing: false };

// Customer email templates per status
const EMAIL_TEMPLATES = {
  'processing': {
    subject: `Your order #${body.number || body.id} is confirmed`,
    body: `<p>Hi ${billing.first_name || 'there'},</p><p>We have received your order and payment is confirmed. We are now preparing your items.</p><p><b>Order #${body.number || body.id}</b> — ${body.currency} ${body.total}</p><p>You will receive another email when your order ships.</p>`
  },
  'completed': {
    subject: `Your order #${body.number || body.id} is complete`,
    body: `<p>Hi ${billing.first_name || 'there'},</p><p>Great news — your order has been fulfilled and is on its way!</p><p><b>Order #${body.number || body.id}</b></p><p>Thank you for your purchase.</p>`
  },
  'on-hold': {
    subject: `Your order #${body.number || body.id} is on hold`,
    body: `<p>Hi ${billing.first_name || 'there'},</p><p>Your order is temporarily on hold while we verify some details. Our team will be in touch shortly.</p><p>If you have questions, please reply to this email.</p>`
  },
  'cancelled': {
    subject: `Your order #${body.number || body.id} has been cancelled`,
    body: `<p>Hi ${billing.first_name || 'there'},</p><p>Your order has been cancelled. If you did not request this or have questions, please contact us.</p><p>If payment was taken, a refund will be processed within 5–7 business days.</p>`
  },
  'refunded': {
    subject: `Refund processed for order #${body.number || body.id}`,
    body: `<p>Hi ${billing.first_name || 'there'},</p><p>Your refund has been processed. Please allow 5–7 business days for it to appear in your account.</p>`
  },
  'failed': {
    subject: `Payment failed for order #${body.number || body.id}`,
    body: `<p>Hi ${billing.first_name || 'there'},</p><p>We were unable to process payment for your order. Please update your payment details or try again.</p><p>Your cart has been saved and you can retry checkout using the link below.</p>`
  }
};

const emailTemplate = EMAIL_TEMPLATES[newStatus] || null;

// Slack team notification
const lineItems = (body.line_items || []).map(i => `• ${i.name} × ${i.quantity}`).join('\n');
const slackMsg = [
  `*Order #${body.number || body.id}* status → *${statusInfo.label}*`,
  `*Customer:* ${billing.first_name || ''} ${billing.last_name || ''} (${billing.email || ''})`,
  `*Total:* ${body.currency} ${body.total}`,
  lineItems
].join('\n');

return [{
  json: {
    order_id:         body.id,
    order_number:     body.number || body.id,
    new_status:       newStatus,
    status_label:     statusInfo.label,
    is_customer_facing: statusInfo.customer_facing,
    customer_email:   billing.email || '',
    customer_name:    `${billing.first_name || ''} ${billing.last_name || ''}`.trim(),
    order_total:      body.total || 0,
    currency:         body.currency || 'USD',
    email_subject:    emailTemplate ? emailTemplate.subject : '',
    email_body:       emailTemplate ? emailTemplate.body    : '',
    should_email:     !!(emailTemplate && billing.email),
    slack_msg:        slackMsg,
    updated_at:       new Date().toISOString()
  }
}];

// ── STEP 1: Classify the problem type and severity ──
const body = $input.first().json.body || $input.first().json;

if (!body.id) {
  throw new Error('Problem order webhook missing order ID');
}

const status = (body.status || '').toLowerCase();
const billing = body.billing || {};
const orderTotal = parseFloat(body.total) || 0;

// Problem classification
const PROBLEM_TYPES = {
  'failed':    { type: 'payment_failed',   severity: 'high',   action_needed: 'Contact customer or retry payment' },
  'cancelled': { type: 'cancelled',        severity: 'medium', action_needed: 'Restock inventory if items were reserved' },
  'refunded':  { type: 'refunded',         severity: 'medium', action_needed: 'Verify refund processed in payment gateway' },
  'on-hold':   { type: 'on_hold',          severity: 'low',    action_needed: 'Review and approve or cancel' }
};

const problemInfo = PROBLEM_TYPES[status];
if (!problemInfo) {
  return [{ json: { skip: true, reason: `Status '${status}' is not a problem status`, order_id: body.id } }];
}

const N8N_BASE_URL = 'https://n8n.sahcreatives.com';
const lineItems = (body.line_items || []).map(i => ({
  product_name: i.name,
  sku: i.sku || String(i.product_id),
  quantity: i.quantity
}));

// Build encoded payload for action URL
const encodedPayload = encodeURIComponent(JSON.stringify({
  order_id: body.id,
  order_number: body.number || body.id,
  status,
  customer_email: billing.email || '',
  customer_name: `${billing.first_name || ''} ${billing.last_name || ''}`.trim(),
  order_total: orderTotal,
  currency: body.currency || 'USD',
  line_items: lineItems
}));

const restockUrl = `${N8N_BASE_URL}/webhook/order-problem-action?action=restock&data=${encodedPayload}`;
const refundUrl  = `${N8N_BASE_URL}/webhook/order-problem-action?action=refund&data=${encodedPayload}`;
const contactUrl = `${N8N_BASE_URL}/webhook/order-problem-action?action=contact&data=${encodedPayload}`;
const noActionUrl = `${N8N_BASE_URL}/webhook/order-problem-action?action=noaction&data=${encodedPayload}`;

// Build Slack message based on problem type
const severityEmoji = { high: ':red_circle:', medium: ':large_yellow_circle:', low: ':white_circle:' };
const emoji = severityEmoji[problemInfo.severity] || ':grey_question:';

const actionButtons = [];
if (status === 'cancelled' || status === 'refunded') actionButtons.push(`<${restockUrl}|Restock inventory>`);
if (status === 'refunded') actionButtons.push(`<${refundUrl}|Confirm refund>`);
if (status === 'failed')   actionButtons.push(`<${contactUrl}|Contact customer>`);
actionButtons.push(`<${noActionUrl}|No action needed>`);

const slackMsg = [
  `${emoji} *Problem Order #${body.number || body.id}* — ${problemInfo.type.replace(/_/g,' ').toUpperCase()}`,
  `*Customer:* ${billing.first_name || ''} ${billing.last_name || ''} (${billing.email || ''})`,
  `*Total:* ${body.currency} ${orderTotal}`,
  `*Items:* ${lineItems.map(i => i.product_name + ' ×' + i.quantity).join(', ')}`,
  `*Severity:* ${problemInfo.severity.toUpperCase()}`,
  `*Suggested action:* ${problemInfo.action_needed}`,
  `\n${actionButtons.join(' | ')}`
].join('\n');

return [{
  json: {
    skip:           false,
    order_id:       body.id,
    order_number:   body.number || body.id,
    status,
    problem_type:   problemInfo.type,
    severity:       problemInfo.severity,
    action_needed:  problemInfo.action_needed,
    customer_email: billing.email || '',
    customer_name:  `${billing.first_name || ''} ${billing.last_name || ''}`.trim(),
    order_total:    orderTotal,
    currency:       body.currency || 'USD',
    line_items:     lineItems,
    slack_msg:      slackMsg,
    logged_at:      new Date().toISOString()
  }
}];

const query = $input.first().json.query || {};
const action = (query.action || '').toLowerCase();

const validActions = ['restock','refund','contact','noaction'];
if (!validActions.includes(action)) {
  throw new Error(`Invalid problem action: "${action}". Expected: ${validActions.join(', ')}`);
}
if (!query.data) {
  throw new Error('Missing order data in problem action URL');
}

let orderData = {};
try {
  orderData = JSON.parse(decodeURIComponent(query.data));
} catch(e) {
  throw new Error(`Could not parse order data: ${e.message}`);
}

if (!orderData.order_id) {
  throw new Error('Order data missing order_id');
}

return [{
  json: {
    action,
    order_id:       orderData.order_id,
    order_number:   orderData.order_number,
    status:         orderData.status,
    customer_email: orderData.customer_email,
    customer_name:  orderData.customer_name,
    order_total:    orderData.order_total,
    currency:       orderData.currency,
    line_items:     orderData.line_items || [],
    actioned_at:    new Date().toISOString()
  }
}];

// Restock: add quantities back to inventory sheet
const order = $input.first().json;
const lineItems = order.line_items || [];

if (lineItems.length === 0) {
  throw new Error(`Order #${order.order_number} has no line items to restock`);
}

// Return one item per line — the Inventory Update Sheet node below
// uses a loop to update each SKU's stock level
return lineItems.map(item => ({
  json: {
    sku:          item.sku,
    product_name: item.product_name,
    qty_to_return: item.quantity,
    order_id:     order.order_id,
    order_number: order.order_number
  }
}));

const item = $('Prepare Restock Items').item.json;
const inventoryRows = $('Read Inventory for Restock').all();

const match = inventoryRows.find(r =>
  (r.json.SKU || '').toString().trim().toLowerCase() === item.sku.toLowerCase()
);

if (!match) {
  throw new Error(`Cannot restock: SKU "${item.sku}" not found in inventory sheet`);
}

const currentStock = parseInt(match.json['Current Stock']) || 0;
const newStock = currentStock + item.qty_to_return;

return [{
  json: {
    sku:         item.sku,
    product_name: item.product_name,
    old_stock:   currentStock,
    new_stock:   newStock,
    qty_returned: item.qty_to_return,
    order_number: item.order_number,
    updated_at:  new Date().toISOString()
  }
}];

// ── Daily audit: SLA check, revenue summary, stuck orders ──
// ── Configuration ──
const SLA_PROCESSING_HOURS = 48;  // orders stuck in 'processing' longer than this = overdue
const SLA_ON_HOLD_HOURS    = 24;  // orders on hold longer than this = needs attention
const HIGH_VALUE_THRESHOLD = 500; // flag high-value open orders in digest

const allOrders    = $('Read Orders Master').all();
const problemOrders = $('Read Problem Orders').all();
const now = Date.now();
const today = new Date();
const yesterday = new Date(today.getFullYear(), today.getMonth(), today.getDate() - 1);

// ─ Yesterday's completed orders for revenue summary ─
const yesterdayOrders = allOrders.filter(r => {
  const created = new Date(r.json['Date Created'] || 0);
  return created >= yesterday && created < today;
});

const yesterdayCompleted = yesterdayOrders.filter(r =>
  ['completed','processing'].includes((r.json.Status || '').toLowerCase())
);

const totalRevenue = yesterdayCompleted.reduce((sum, r) =>
  sum + (parseFloat(r.json['Order Total']) || 0), 0
);
const avgOrderValue = yesterdayCompleted.length > 0
  ? (totalRevenue / yesterdayCompleted.length).toFixed(2)
  : 0;

// ─ SLA breach: orders stuck in processing > 48h ─
const stuckProcessing = allOrders.filter(r => {
  const status = (r.json.Status || '').toLowerCase();
  if (status !== 'processing') return false;
  const logged = new Date(r.json['Logged At'] || r.json['Date Created'] || 0).getTime();
  const ageHours = (now - logged) / 3600000;
  return ageHours > SLA_PROCESSING_HOURS;
}).map(r => ({
  order_number: r.json['Order Number'] || r.json['Order ID'],
  customer:     r.json['Customer Name'],
  total:        r.json['Order Total'],
  logged_at:    r.json['Logged At']
}));

// ─ On hold > 24h ─
const stuckOnHold = allOrders.filter(r => {
  const status = (r.json.Status || '').toLowerCase();
  if (status !== 'on-hold') return false;
  const logged = new Date(r.json['Logged At'] || r.json['Date Created'] || 0).getTime();
  const ageHours = (now - logged) / 3600000;
  return ageHours > SLA_ON_HOLD_HOURS;
}).map(r => ({
  order_number: r.json['Order Number'] || r.json['Order ID'],
  customer:     r.json['Customer Name'],
  total:        r.json['Order Total']
}));

// ─ Open problem orders unresolved ─
const openProblems = problemOrders.filter(r =>
  (r.json.Status || '').toLowerCase() === 'open'
).map(r => ({
  order_number: r.json['Order Number'],
  problem_type: r.json['Problem Type'],
  severity:     r.json['Severity'],
  customer:     r.json['Customer Email'],
  logged_at:    r.json['Logged At']
}));

// ─ Flagged orders still unresolved ─
const openFlagged = allOrders.filter(r =>
  r.json.Flagged === 'YES' &&
  ['processing','on-hold'].includes((r.json.Status || '').toLowerCase())
).length;

// ─ Build Slack digest ─
const lines = [
  `:bar_chart: *Daily Order Digest — ${today.toDateString()}*`,
  '',
  `*Yesterday:* ${yesterdayCompleted.length} orders | Revenue: ${yesterdayCompleted[0]?.json?.Currency || 'USD'} ${totalRevenue.toFixed(2)} | Avg: ${yesterdayCompleted[0]?.json?.Currency || 'USD'} ${avgOrderValue}`,
  ''
];

if (stuckProcessing.length > 0) {
  lines.push(`:warning: *SLA Breach — ${stuckProcessing.length} order(s) stuck in processing >48h:*`);
  stuckProcessing.forEach(o => lines.push(`  • Order #${o.order_number} — ${o.customer} (${o.total})`));
  lines.push('');
}

if (stuckOnHold.length > 0) {
  lines.push(`:large_yellow_circle: *On Hold >24h — ${stuckOnHold.length} order(s) need attention:*`);
  stuckOnHold.forEach(o => lines.push(`  • Order #${o.order_number} — ${o.customer} (${o.total})`));
  lines.push('');
}

if (openProblems.length > 0) {
  lines.push(`:red_circle: *Unresolved Problems — ${openProblems.length} open issue(s):*`);
  openProblems.forEach(o => lines.push(`  • Order #${o.order_number} — ${o.problem_type} (${o.severity}) — ${o.customer}`));
  lines.push('');
}

if (openFlagged > 0) {
  lines.push(`:rotating_light: ${openFlagged} flagged order(s) still awaiting review in #order-review`);
  lines.push('');
}

if (stuckProcessing.length === 0 && stuckOnHold.length === 0 && openProblems.length === 0) {
  lines.push(':white_check_mark: No SLA breaches or unresolved issues. All clear.');
}

return [{
  json: {
    date:                today.toISOString().slice(0, 10),
    orders_yesterday:    yesterdayCompleted.length,
    revenue_yesterday:   totalRevenue.toFixed(2),
    avg_order_value:     avgOrderValue,
    stuck_processing:    stuckProcessing.length,
    stuck_on_hold:       stuckOnHold.length,
    open_problems:       openProblems.length,
    open_flagged:        openFlagged,
    slack_digest:        lines.join('\n'),
    has_alerts:          stuckProcessing.length > 0 || stuckOnHold.length > 0 || openProblems.length > 0
  }
}];
